export type SourceStatus = "draft" | "active" | "deprecated" | "archived";
export type SourceType = "research-paper" | "clinical-guideline" | "book" | "official-documentation" | "official-website" | "technical-documentation" | "product-documentation" | "internal-document" | "regulatory-source" | "news-source" | "dataset" | "standard" | "manual" | "expert-review" | "professional-review" | "user-provided-source";
export type SourceTrustLevel = "unknown" | "low" | "medium" | "high" | "authoritative";
export type KnowledgeSource = {
    id: string;
    type: SourceType;
    title: string;
    status: SourceStatus;
    authors?: string[];
    publisher?: string;
    url?: string;
    doi?: string;
    isbn?: string;
    publicationDate?: string;
    accessedAt?: string;
    language?: string;
    version?: string;
    summary?: string;
    trustLevel?: SourceTrustLevel;
    freshness?: "stable" | "periodic" | "time-sensitive" | "outdated";
    visibility?: "public" | "internal" | "private";
    createdAt: string;
    updatedAt: string;
};
export type CitationStatus = "draft" | "active" | "deprecated" | "removed";
export type CitationPurpose = "supports" | "explains" | "defines" | "contrasts" | "updates" | "corrects" | "reviews" | "verifies" | "credits" | "references";
export type CitationConfidence = "low" | "medium" | "high" | "authoritative";
export type KnowledgeCitation = {
    id: string;
    sourceId: string;
    targetId: string;
    claimId?: string;
    purpose: CitationPurpose;
    status: CitationStatus;
    quote?: string;
    paraphrase?: string;
    page?: string;
    section?: string;
    url?: string;
    confidence?: CitationConfidence;
    relevance?: "low" | "medium" | "high";
    addedBy?: string;
    reviewedBy?: string;
    reviewedAt?: string;
    notes?: string;
    createdAt: string;
    updatedAt: string;
};
